interface Renderer {
  renderCircle(radius: number): void
}

class CanvasRenderer implements Renderer {
  renderCircle(r: number) { console.log('canvas ' + r) }
}

class Circle {
  constructor(private renderer: Renderer, private radius: number) {}
  draw() { this.renderer.renderCircle(this.radius) }
}

// Version A
interface Renderer { render(shapeDesc: string): void }
class VectorRenderer implements Renderer { render(s: string) { console.log('vector ' + s) } }
class RasterRenderer implements Renderer { render(s: string) { console.log('raster ' + s) } }

abstract class Shape {
  constructor(protected renderer: Renderer) {}
  abstract draw(): void
}

class Circle extends Shape {
  constructor(renderer: Renderer, private radius: number) { super(renderer) }
  draw() { this.renderer.render(`Circle radius ${this.radius}`) }
}

